DECLARE envbq_status number; valor_envbq_update number; vro_error tkr_errores%ROWTYPE; BEGIN -- Caso INSERT IF INSERTING THEN
SELECT (SELECT ENVIO_BQ FROM TKRBQ_ENTIDADES WHERE ID = :NEW.ID AND ENVIO_BQ != 1) INTO envbq_status FROM DUAL;
IF envbq_status IS NOT NULL THEN DELETE TKRBQ_ENTIDADES WHERE ID = :NEW.ID AND ENVIO_BQ != 1; END IF;
INSERT INTO TKRBQ_ENTIDADES ( ENVIO_BQ, ID, NOMBRE_ENTIDAD, ID_TIPO_ENTIDAD, TIPO_ALIADO, NOMBRE_REPRESENTANTE, CARGO_REPRESENTANTE, CORREO_ELECTRONICO, TELEFONO, ID_MEDIO, MENSAJE_REGISTRO, ID_TIPO_IDENTIFICACION, IDENTIFICACION, FECHA_REGISTRO, ID_ESTADO_ENTIDAD, TELEFONO_SOPORTE, RUTA_CONSENTIMIENTO_PACIENTE, ID_CODIGO_DESCUENTO, NOMBRE_LOGO, DIRECCION, ID_CIUDAD, RUTA_LOGO, PUEDE_VER_HISTORIA, TIEMPO_CITA, FECHA_CREACION, PREGUNTAR_COPAGO, TIENE_COPAGO, PAGA_DESPUES, PAGA_PACIENTE, OBLIGATORIO_ESCALA, RESTRINGIR_DOCUMENTOS_PACIENTE, CODIGO_DOCUMENTO_CIP, OCULTAR_PRECIO_DIRECTORIO, VER_DIRECTORIO, RUTA_DASHBOARD, MOSTRAR_ESCALAS, NUMERO_TELEFONO_SOPORTE, SUBIR_ARCHIVOS_CITA, COPAGO_MONITOREO, ID_CONVENIO_DEFECTO, AGENDAR_CHAT, CENTRO_COSTO, TIPO_ASEGURAMIENTO, CADENA_HASH, ID_CONVENIO_TQ, MINUTOS_DISPONIBILIDAD, REQUIERE_AUTORIZACION, ID_TIPO_ALIADO, VER_TODAS_ESPECIALIDADES, DESCUENTO_COMERCIAL, RESERVAR_AGENDA, COPAGO_ESTANDAR ) VALUES ( 0, -- ENVIO_BQ para INSERT :NEW.ID, :NEW.NOMBRE_ENTIDAD, :NEW.ID_TIPO_ENTIDAD, :NEW.TIPO_ALIADO, :NEW.NOMBRE_REPRESENTANTE, :NEW.CARGO_REPRESENTANTE, :NEW.CORREO_ELECTRONICO, :NEW.TELEFONO, :NEW.ID_MEDIO, :NEW.MENSAJE_REGISTRO, :NEW.ID_TIPO_IDENTIFICACION, :NEW.IDENTIFICACION, :NEW.FECHA_REGISTRO, :NEW.ID_ESTADO_ENTIDAD, :NEW.TELEFONO_SOPORTE, :NEW.RUTA_CONSENTIMIENTO_PACIENTE, :NEW.ID_CODIGO_DESCUENTO, :NEW.NOMBRE_LOGO, :NEW.DIRECCION, :NEW.ID_CIUDAD, :NEW.RUTA_LOGO, :NEW.PUEDE_VER_HISTORIA, :NEW.TIEMPO_CITA, :NEW.FECHA_CREACION, :NEW.PREGUNTAR_COPAGO, :NEW.TIENE_COPAGO, :NEW.PAGA_DESPUES, :NEW.PAGA_PACIENTE, :NEW.OBLIGATORIO_ESCALA, :NEW.RESTRINGIR_DOCUMENTOS_PACIENTE, :NEW.CODIGO_DOCUMENTO_CIP, :NEW.OCULTAR_PRECIO_DIRECTORIO, :NEW.VER_DIRECTORIO, :NEW.RUTA_DASHBOARD, :NEW.MOSTRAR_ESCALAS, :NEW.NUMERO_TELEFONO_SOPORTE, :NEW.SUBIR_ARCHIVOS_CITA, :NEW.COPAGO_MONITOREO, :NEW.ID_CONVENIO_DEFECTO, :NEW.AGENDAR_CHAT, :NEW.CENTRO_COSTO, :NEW.TIPO_ASEGURAMIENTO, :NEW.CADENA_HASH, :NEW.ID_CONVENIO_TQ, :NEW.MINUTOS_DISPONIBILIDAD, :NEW.REQUIERE_AUTORIZACION, :NEW.ID_TIPO_ALIADO, :NEW.VER_TODAS_ESPECIALIDADES, :NEW.DESCUENTO_COMERCIAL, :NEW.RESERVAR_AGENDA, :NEW.COPAGO_ESTANDAR ); END IF;
-- Caso UPDATE IF UPDATING THEN SELECT (SELECT ENVIO_BQ FROM TKRBQ_ENTIDADES WHERE ID = :NEW.ID AND ENVIO_BQ != 1 AND ROWNUM <= 1) INTO envbq_status FROM DUAL;
IF envbq_status IS NULL THEN
INSERT INTO TKRBQ_ENTIDADES ( ENVIO_BQ, ID, NOMBRE_ENTIDAD, ID_TIPO_ENTIDAD, TIPO_ALIADO, NOMBRE_REPRESENTANTE, CARGO_REPRESENTANTE, CORREO_ELECTRONICO, TELEFONO, ID_MEDIO, MENSAJE_REGISTRO, ID_TIPO_IDENTIFICACION, IDENTIFICACION, FECHA_REGISTRO, ID_ESTADO_ENTIDAD, TELEFONO_SOPORTE, RUTA_CONSENTIMIENTO_PACIENTE, ID_CODIGO_DESCUENTO, NOMBRE_LOGO, DIRECCION, ID_CIUDAD, RUTA_LOGO, PUEDE_VER_HISTORIA, TIEMPO_CITA, FECHA_CREACION, PREGUNTAR_COPAGO, TIENE_COPAGO, PAGA_DESPUES, PAGA_PACIENTE, OBLIGATORIO_ESCALA, RESTRINGIR_DOCUMENTOS_PACIENTE, CODIGO_DOCUMENTO_CIP, OCULTAR_PRECIO_DIRECTORIO, VER_DIRECTORIO, RUTA_DASHBOARD, MOSTRAR_ESCALAS, NUMERO_TELEFONO_SOPORTE, SUBIR_ARCHIVOS_CITA, COPAGO_MONITOREO, ID_CONVENIO_DEFECTO, AGENDAR_CHAT, CENTRO_COSTO, TIPO_ASEGURAMIENTO, CADENA_HASH, ID_CONVENIO_TQ, MINUTOS_DISPONIBILIDAD, REQUIERE_AUTORIZACION, ID_TIPO_ALIADO, VER_TODAS_ESPECIALIDADES, DESCUENTO_COMERCIAL, RESERVAR_AGENDA, COPAGO_ESTANDAR ) VALUES ( 2, -- ENVIO_BQ para INSERT :NEW.ID, :NEW.NOMBRE_ENTIDAD, :NEW.ID_TIPO_ENTIDAD, :NEW.TIPO_ALIADO, :NEW.NOMBRE_REPRESENTANTE, :NEW.CARGO_REPRESENTANTE, :NEW.CORREO_ELECTRONICO, :NEW.TELEFONO, :NEW.ID_MEDIO, :NEW.MENSAJE_REGISTRO, :NEW.ID_TIPO_IDENTIFICACION, :NEW.IDENTIFICACION, :NEW.FECHA_REGISTRO, :NEW.ID_ESTADO_ENTIDAD, :NEW.TELEFONO_SOPORTE, :NEW.RUTA_CONSENTIMIENTO_PACIENTE, :NEW.ID_CODIGO_DESCUENTO, :NEW.NOMBRE_LOGO, :NEW.DIRECCION, :NEW.ID_CIUDAD, :NEW.RUTA_LOGO, :NEW.PUEDE_VER_HISTORIA, :NEW.TIEMPO_CITA, :NEW.FECHA_CREACION, :NEW.PREGUNTAR_COPAGO, :NEW.TIENE_COPAGO, :NEW.PAGA_DESPUES, :NEW.PAGA_PACIENTE, :NEW.OBLIGATORIO_ESCALA, :NEW.RESTRINGIR_DOCUMENTOS_PACIENTE, :NEW.CODIGO_DOCUMENTO_CIP, :NEW.OCULTAR_PRECIO_DIRECTORIO, :NEW.VER_DIRECTORIO, :NEW.RUTA_DASHBOARD, :NEW.MOSTRAR_ESCALAS, :NEW.NUMERO_TELEFONO_SOPORTE, :NEW.SUBIR_ARCHIVOS_CITA, :NEW.COPAGO_MONITOREO, :NEW.ID_CONVENIO_DEFECTO, :NEW.AGENDAR_CHAT, :NEW.CENTRO_COSTO, :NEW.TIPO_ASEGURAMIENTO, :NEW.CADENA_HASH, :NEW.ID_CONVENIO_TQ, :NEW.MINUTOS_DISPONIBILIDAD, :NEW.REQUIERE_AUTORIZACION, :NEW.ID_TIPO_ALIADO, :NEW.VER_TODAS_ESPECIALIDADES, :NEW.DESCUENTO_COMERCIAL, :NEW.RESERVAR_AGENDA, :NEW.COPAGO_ESTANDAR );
ELSE
IF envbq_status = 0 THEN valor_envbq_update := 0; ELSE valor_envbq_update := 2; END IF;
UPDATE TKRBQ_ENTIDADES SET ENVIO_BQ = valor_envbq_update, ID = :NEW.ID, NOMBRE_ENTIDAD = :NEW.NOMBRE_ENTIDAD, ID_TIPO_ENTIDAD = :NEW.ID_TIPO_ENTIDAD, TIPO_ALIADO = :NEW.TIPO_ALIADO, NOMBRE_REPRESENTANTE = :NEW.NOMBRE_REPRESENTANTE, CARGO_REPRESENTANTE = :NEW.CARGO_REPRESENTANTE, CORREO_ELECTRONICO = :NEW.CORREO_ELECTRONICO, TELEFONO = :NEW.TELEFONO, ID_MEDIO = :NEW.ID_MEDIO, MENSAJE_REGISTRO = :NEW.MENSAJE_REGISTRO, ID_TIPO_IDENTIFICACION = :NEW.ID_TIPO_IDENTIFICACION, IDENTIFICACION = :NEW.IDENTIFICACION, FECHA_REGISTRO = :NEW.FECHA_REGISTRO, ID_ESTADO_ENTIDAD = :NEW.ID_ESTADO_ENTIDAD, TELEFONO_SOPORTE = :NEW.TELEFONO_SOPORTE, RUTA_CONSENTIMIENTO_PACIENTE = :NEW.RUTA_CONSENTIMIENTO_PACIENTE, ID_CODIGO_DESCUENTO = :NEW.ID_CODIGO_DESCUENTO, NOMBRE_LOGO = :NEW.NOMBRE_LOGO, DIRECCION = :NEW.DIRECCION, ID_CIUDAD = :NEW.ID_CIUDAD, RUTA_LOGO = :NEW.RUTA_LOGO, PUEDE_VER_HISTORIA = :NEW.PUEDE_VER_HISTORIA, TIEMPO_CITA = :NEW.TIEMPO_CITA, FECHA_CREACION = :NEW.FECHA_CREACION, PREGUNTAR_COPAGO = :NEW.PREGUNTAR_COPAGO, TIENE_COPAGO = :NEW.TIENE_COPAGO, PAGA_DESPUES = :NEW.PAGA_DESPUES, PAGA_PACIENTE = :NEW.PAGA_PACIENTE, OBLIGATORIO_ESCALA = :NEW.OBLIGATORIO_ESCALA, RESTRINGIR_DOCUMENTOS_PACIENTE = :NEW.RESTRINGIR_DOCUMENTOS_PACIENTE, CODIGO_DOCUMENTO_CIP = :NEW.CODIGO_DOCUMENTO_CIP, OCULTAR_PRECIO_DIRECTORIO = :NEW.OCULTAR_PRECIO_DIRECTORIO, VER_DIRECTORIO = :NEW.VER_DIRECTORIO, RUTA_DASHBOARD = :NEW.RUTA_DASHBOARD, MOSTRAR_ESCALAS = :NEW.MOSTRAR_ESCALAS, NUMERO_TELEFONO_SOPORTE = :NEW.NUMERO_TELEFONO_SOPORTE, SUBIR_ARCHIVOS_CITA = :NEW.SUBIR_ARCHIVOS_CITA, COPAGO_MONITOREO = :NEW.COPAGO_MONITOREO, ID_CONVENIO_DEFECTO = :NEW.ID_CONVENIO_DEFECTO, AGENDAR_CHAT = :NEW.AGENDAR_CHAT, CENTRO_COSTO = :NEW.CENTRO_COSTO, TIPO_ASEGURAMIENTO = :NEW.TIPO_ASEGURAMIENTO, CADENA_HASH = :NEW.CADENA_HASH, ID_CONVENIO_TQ = :NEW.ID_CONVENIO_TQ, MINUTOS_DISPONIBILIDAD = :NEW.MINUTOS_DISPONIBILIDAD, REQUIERE_AUTORIZACION = :NEW.REQUIERE_AUTORIZACION, ID_TIPO_ALIADO = :NEW.ID_TIPO_ALIADO, VER_TODAS_ESPECIALIDADES = :NEW.VER_TODAS_ESPECIALIDADES, DESCUENTO_COMERCIAL = :NEW.DESCUENTO_COMERCIAL, RESERVAR_AGENDA = :NEW.RESERVAR_AGENDA, COPAGO_ESTANDAR = :NEW.COPAGO_ESTANDAR WHERE ID = :OLD.ID AND ENVIO_BQ != 1; END IF; END IF;
-- Caso DELETE IF DELETING THEN
SELECT (SELECT ENVIO_BQ FROM TKRBQ_ENTIDADES WHERE ID = :OLD.ID AND ENVIO_BQ != 1 AND ROWNUM <= 1) INTO envbq_status FROM DUAL;
IF envbq_status IS NOT NULL THEN DELETE TKRBQ_ENTIDADES WHERE ID = :OLD.ID AND ENVIO_BQ != 1; END IF;
INSERT INTO TKRBQ_ENTIDADES ( ENVIO_BQ, ID, NOMBRE_ENTIDAD, ID_TIPO_ENTIDAD, TIPO_ALIADO, NOMBRE_REPRESENTANTE, CARGO_REPRESENTANTE, CORREO_ELECTRONICO, TELEFONO, ID_MEDIO, MENSAJE_REGISTRO, ID_TIPO_IDENTIFICACION, IDENTIFICACION, FECHA_REGISTRO, ID_ESTADO_ENTIDAD, TELEFONO_SOPORTE, RUTA_CONSENTIMIENTO_PACIENTE, ID_CODIGO_DESCUENTO, NOMBRE_LOGO, DIRECCION, ID_CIUDAD, RUTA_LOGO, PUEDE_VER_HISTORIA, TIEMPO_CITA, FECHA_CREACION, PREGUNTAR_COPAGO, TIENE_COPAGO, PAGA_DESPUES, PAGA_PACIENTE, OBLIGATORIO_ESCALA, RESTRINGIR_DOCUMENTOS_PACIENTE, CODIGO_DOCUMENTO_CIP, OCULTAR_PRECIO_DIRECTORIO, VER_DIRECTORIO, RUTA_DASHBOARD, MOSTRAR_ESCALAS, NUMERO_TELEFONO_SOPORTE, SUBIR_ARCHIVOS_CITA, COPAGO_MONITOREO, ID_CONVENIO_DEFECTO, AGENDAR_CHAT, CENTRO_COSTO, TIPO_ASEGURAMIENTO, CADENA_HASH, ID_CONVENIO_TQ, MINUTOS_DISPONIBILIDAD, REQUIERE_AUTORIZACION, ID_TIPO_ALIADO, VER_TODAS_ESPECIALIDADES, DESCUENTO_COMERCIAL, RESERVAR_AGENDA, COPAGO_ESTANDAR ) VALUES ( -1, -- ENVIO_BQ para DELETE :OLD.ID, :OLD.NOMBRE_ENTIDAD, :OLD.ID_TIPO_ENTIDAD, :OLD.TIPO_ALIADO, :OLD.NOMBRE_REPRESENTANTE, :OLD.CARGO_REPRESENTANTE, :OLD.CORREO_ELECTRONICO, :OLD.TELEFONO, :OLD.ID_MEDIO, :OLD.MENSAJE_REGISTRO, :OLD.ID_TIPO_IDENTIFICACION, :OLD.IDENTIFICACION, :OLD.FECHA_REGISTRO, :OLD.ID_ESTADO_ENTIDAD, :OLD.TELEFONO_SOPORTE, :OLD.RUTA_CONSENTIMIENTO_PACIENTE, :OLD.ID_CODIGO_DESCUENTO, :OLD.NOMBRE_LOGO, :OLD.DIRECCION, :OLD.ID_CIUDAD, :OLD.RUTA_LOGO, :OLD.PUEDE_VER_HISTORIA, :OLD.TIEMPO_CITA, :OLD.FECHA_CREACION, :OLD.PREGUNTAR_COPAGO, :OLD.TIENE_COPAGO, :OLD.PAGA_DESPUES, :OLD.PAGA_PACIENTE, :OLD.OBLIGATORIO_ESCALA, :OLD.RESTRINGIR_DOCUMENTOS_PACIENTE, :OLD.CODIGO_DOCUMENTO_CIP, :OLD.OCULTAR_PRECIO_DIRECTORIO, :OLD.VER_DIRECTORIO, :OLD.RUTA_DASHBOARD, :OLD.MOSTRAR_ESCALAS, :OLD.NUMERO_TELEFONO_SOPORTE, :OLD.SUBIR_ARCHIVOS_CITA, :OLD.COPAGO_MONITOREO, :OLD.ID_CONVENIO_DEFECTO, :OLD.AGENDAR_CHAT, :OLD.CENTRO_COSTO, :OLD.TIPO_ASEGURAMIENTO, :OLD.CADENA_HASH, :OLD.ID_CONVENIO_TQ, :OLD.MINUTOS_DISPONIBILIDAD, :OLD.REQUIERE_AUTORIZACION, :OLD.ID_TIPO_ALIADO, :OLD.VER_TODAS_ESPECIALIDADES, :OLD.DESCUENTO_COMERCIAL, :OLD.RESERVAR_AGENDA, :OLD.COPAGO_ESTANDAR ); END IF;
EXCEPTION WHEN OTHERS THEN vro_error.nombre_programa := 'TRG_SYNC_TKR_ENTIDADES'; vro_error.nombre_metodo := 'TRIGGER_SYNC_BQ'; vro_error.parametros := 'id de consultas: '||:old.id; uti_ge_excepciones_pkg.p_grabar_log (vro_error);
END;
